(function(){
    $.ajaxSetup({ cache: false });
loadselects=function (){
    $.each($('[data-init-function]'),function(k,v){
        var element = $(v);
        var functionName = element.data('init-function');
        if (typeof window[functionName] === "function") {
            window[functionName](element);
        }
    });
}
set_lang=function(e){
    
    if($(e).data('text') !== undefined){
        $(e).html($(e).data('text'));
    }
}
set_data=function(e){
    var text=$(e).data('text')
    $(e).html(requestUserData[text]);
}
setlogo=function(){
    $logo=' data:image/gif;base64,';
    $('#polarimg').attr('src',$logo)
    
}
SETQRCODE=function(e) {
    var data = $('input[data-init-function=SETQRCODE]').val();
    var ap = websitelink + '/api/QRCODE';
    var target_link = websitelink + '/QRCODE/' + data;
    ll = new URL(target_link)
    $('.SETQRCODE').qrcode({
        mode: 0,
        render: 'canvas',
        minVersion: 1,
        maxVersion: 40,
        ecLevel: 'L',
        left: 0,
        top: 0,
        size: 180,
        fill: '#000',
        background: '#fff',
        radius: 0,
        quiet: 0,
        mSize: 0.1,
        mPosX: 0.5,
        mPosY: 0.5,
        text:ll.href,
    
    });
}
setlogo();
loadselects();
})(jQuery)
